        }

        char m = get_mirror_char(c);

        // Check if m is a character that appeared in the string or if c and m are the same
        // If m is not in the string, freq[m] will return 0 due to map's default behavior, which is correct.
        int count_m = freq.count(m) ? freq[m] : 0;

        if (c == m) {
            // Case 1: c is its own mirror (e.g., 'm' <-> 'n' is not self-mirror, but 'x' <-> 'c' is not self-mirror,
            // self-mirror only happens if the character is exactly in the middle, e.g., 'm' in alphabet size 26, 
            // but for alphabet/digits, there are no self-mirrors unless the set size is odd and we are at the center, 
            // which is not the case for 'a'-'z' or '0'-'9' when paired symmetrically. 
            // However, if c==m, we calculate the difference and mark it processed.)
            // For example, if 'x' mapped to 'x', we calculate |freq(x) - freq(x)| = 0.
            total_diff_sum += abs(count_c - count_m);
            processed.insert(c);
        } else if (c < m) { 
            // Case 2: c and m form a unique pair (c < m ensures we process the pair only once, e.g., (b, y) but not (y, b))
            // We rely on the ordering property of characters to ensure uniqueness.

            // Calculate |freq(c) - freq(m)|
            total_diff_sum += abs(count_c - count_m);

            // Mark both c and m as processed
            processed.insert(c);
            processed.insert(m);
        } 
        // Case 3: c > m. This pair (m, c) would have already been processed when iterating over m, 
        // or m is not in the map/string, which is handled implicitly by checking processed set and the c < m condition above.
        // If c > m, and m is in the string, m would have been encountered before c (due to map iteration order, which is by key).
    }

    return total_diff_sum;
}
